patch:
diff --git a/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp b/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
index a88f8f19f852..b9378451ac43 100644
--- a/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
+++ b/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
@@ -604,6 +604,16 @@ APInt ConstantOffsetExtractor::find(Value *V, bool SignExtended,
     else if (BO->getOpcode() == Instruction::Xor)
       ConstantOffset = extractDisjointBitsFromXor(BO);
   } else if (isa<TruncInst>(V)) {
+    // Do not trace through poison-generating truncs with nsw/nuw. Moving such
+    // casts across arithmetic can change when poison is produced and is
+    // unsound. Only trace through plain trunc without no-wrap flags.
+    const TruncInst *TI = cast<TruncInst>(V);
+    if (TI->hasNoUnsignedWrap() || TI->hasNoSignedWrap()) {
+      // Treat as a barrier: no constant offset extracted through this node.
+      // Leave the trunc in place to preserve original poison semantics.
+      // Return zero so this instruction won't be added to UserChain.
+      return APInt(BitWidth, 0);
+    }
     ConstantOffset =
         find(U->getOperand(0), SignExtended, ZeroExtended, NonNegative)
             .trunc(BitWidth);

